BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'CABG & PCI' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'CABG & PCI', 'Revascularization indications and post-op priorities', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - CABG and PCI (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'CABG and PCI - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports CAD progression in this revascularization scenario?', 'Which finding most strongly supports CAD progression in this revascularization scenario?', '[{"id": "a", "text": "CAD progression listed is stable angina to unstable angina to NSTEMI to STEMI."}, {"id": "b", "text": "STEMI is earliest stage in this note."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "This pattern is more consistent with Primary PCI timing."}]'::jsonb, '["a"]'::jsonb, 'Correct because CAD progression listed is stable angina to unstable angina to NSTEMI to STEMI. Escalating symptoms should trigger faster revascularization decisions.', 'CABG and PCI - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches Revascularization options?', 'The nurse reviews post-procedure data; which interpretation best matches Revascularization options?', '[{"id": "a", "text": "EF is irrelevant to decision in this note."}, {"id": "b", "text": "Procedure choice must match anatomy and risk profile, not convenience."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "This pattern is more consistent with PCI indications."}]'::jsonb, '["b"]'::jsonb, 'Correct because Two options are PCI (less invasive) and CABG (surgery), selected by vessel count, anatomy, EF, and comorbidities. Procedure choice must match anatomy and risk profile, not convenience.', 'CABG and PCI - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding PCI basics?', 'Which clinical judgment is most accurate regarding PCI basics?', '[{"id": "a", "text": "This pattern is more consistent with Pre-PCI preparation."}, {"id": "b", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "c", "text": "PCI is catheter-based via radial or femoral access, using balloon angioplasty and often stent placement."}, {"id": "d", "text": "Post-procedure education has minimal impact on outcomes."}]'::jsonb, '["c"]'::jsonb, 'Correct because PCI is catheter-based via radial or femoral access, using balloon angioplasty and often stent placement. Monitor access-site and reperfusion outcomes immediately post-procedure.', 'CABG and PCI - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Drug-eluting stent role?', 'In urgent triage, which conclusion aligns with Drug-eluting stent role?', '[{"id": "a", "text": "This pattern is more consistent with Post-PCI vitals and site care."}, {"id": "b", "text": "DES increases restenosis intentionally in this note."}, {"id": "c", "text": "Maintain antiplatelet adherence to prevent stent thrombosis/restenosis."}, {"id": "d", "text": "Frequent reassessment can be delayed when initial vitals are stable."}]'::jsonb, '["c"]'::jsonb, 'Correct because Drug-eluting stents contain antiproliferative medication to reduce restenosis. Maintain antiplatelet adherence to prevent stent thrombosis/restenosis.', 'CABG and PCI - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Primary PCI timing from this note?', 'Which statement best reflects Primary PCI timing from this note?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "Primary PCI is treatment of choice for STEMI with door-to-balloon goal within 90 minutes."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Primary PCI target is 24 hours in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Primary PCI is treatment of choice for STEMI with door-to-balloon goal within 90 minutes. Time-to-balloon directly impacts myocardial salvage.', 'CABG and PCI - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports PCI indications in this revascularization scenario?', 'Which finding most strongly supports PCI indications in this revascularization scenario?', '[{"id": "a", "text": "This pattern is more consistent with Post-PCI medication adherence."}, {"id": "b", "text": "Use PCI when anatomy and risk profile make catheter strategy appropriate."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Frequent reassessment can be delayed when initial vitals are stable."}]'::jsonb, '["b"]'::jsonb, 'Correct because PCI indications include STEMI/NSTEMI, refractory unstable angina, suitable 1–2 vessel disease, or high CABG surgical risk. Use PCI when anatomy and risk profile make catheter strategy appropriate.', 'CABG and PCI - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches Pre-PCI preparation?', 'The nurse reviews post-procedure data; which interpretation best matches Pre-PCI preparation?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "This pattern is more consistent with PCI complications."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Pre-PCI care includes NPO 4–6 hours, IV access, type and screen, DAPT initiation, anticoagulation, creatinine check, and pulse marking."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pre-PCI care includes NPO 4–6 hours, IV access, type and screen, DAPT initiation, anticoagulation, creatinine check, and pulse marking. Optimize safety by preparing bleeding, renal, and access monitoring plans.', 'CABG and PCI - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Post-PCI vitals and site care?', 'Which clinical judgment is most accurate regarding Post-PCI vitals and site care?', '[{"id": "a", "text": "Site checks are unnecessary after sheath removal in this note."}, {"id": "b", "text": "Vitals can be deferred for several hours in this note."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "Early detection of access complications prevents deterioration."}]'::jsonb, '["d"]'::jsonb, 'Correct because Post-PCI protocol includes frequent vitals and puncture site checks for bleeding/hematoma. Early detection of access complications prevents deterioration.', 'CABG and PCI - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Post-PCI limb and hydration?', 'In urgent triage, which conclusion aligns with Post-PCI limb and hydration?', '[{"id": "a", "text": "This pattern is more consistent with CABG graft options."}, {"id": "b", "text": "Femoral approach requires limb straight with bedrest 4–6 hours; fluids are encouraged to clear contrast."}, {"id": "c", "text": "Immediate vigorous leg flexion is recommended in this note."}, {"id": "d", "text": "Frequent reassessment can be delayed when initial vitals are stable."}]'::jsonb, '["b"]'::jsonb, 'Correct because Femoral approach requires limb straight with bedrest 4–6 hours; fluids are encouraged to clear contrast. Protect access integrity while lowering nephropathy risk.', 'CABG and PCI - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Post-PCI medication adherence from this note?', 'Which statement best reflects Post-PCI medication adherence from this note?', '[{"id": "a", "text": "This pattern is more consistent with CABG indications high risk anatomy."}, {"id": "b", "text": "DAPT stops after 48 hours in this note."}, {"id": "c", "text": "Nonadherence significantly raises stent thrombosis risk."}, {"id": "d", "text": "Post-procedure education has minimal impact on outcomes."}]'::jsonb, '["c"]'::jsonb, 'Correct because Dual antiplatelet therapy is required for at least 1 year after stent placement. Nonadherence significantly raises stent thrombosis risk.', 'CABG and PCI - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports PCI complications in this revascularization scenario?', 'Which finding most strongly supports PCI complications in this revascularization scenario?', '[{"id": "a", "text": "PCI has no renal complications in this note."}, {"id": "b", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "Listed PCI complications include access-site bleeding (most common), contrast nephropathy, arterial dissection, restenosis/re-occlusion, and stent thrombosis."}]'::jsonb, '["d"]'::jsonb, 'Correct because Listed PCI complications include access-site bleeding (most common), contrast nephropathy, arterial dissection, restenosis/re-occlusion, and stent thrombosis. Monitor for ischemic recurrence and bleeding/renal complications continuously.', 'CABG and PCI - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches CABG definition?', 'The nurse reviews post-procedure data; which interpretation best matches CABG definition?', '[{"id": "a", "text": "CABG avoids any graft vessel use in this note."}, {"id": "b", "text": "Post-op priorities focus on airway, hemodynamics, and graft-related complications."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Frequent reassessment can be delayed when initial vitals are stable."}]'::jsonb, '["b"]'::jsonb, 'Correct because CABG is open-heart bypass surgery using grafts to route blood around blocked coronaries. Post-op priorities focus on airway, hemodynamics, and graft-related complications.', 'CABG and PCI - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding CABG graft options?', 'Which clinical judgment is most accurate regarding CABG graft options?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "Graft choices include reversed saphenous vein, internal mammary artery (most durable to LAD), and radial artery."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Only synthetic grafts are used in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Graft choices include reversed saphenous vein, internal mammary artery (most durable to LAD), and radial artery. Understand graft source/patency differences for long-term follow-up education.', 'CABG and PCI - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with CABG indications high risk anatomy?', 'In urgent triage, which conclusion aligns with CABG indications high risk anatomy?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "This pattern is more consistent with Chest tube handling."}, {"id": "c", "text": "Escalate to surgical strategy for high-risk multivessel anatomy."}, {"id": "d", "text": "Single-vessel mild disease always requires CABG in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because CABG indications include left main disease >50%, 3-vessel CAD especially with reduced EF, and proximal LAD involvement. Escalate to surgical strategy for high-risk multivessel anatomy.', 'CABG and PCI - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Other CABG indications from this note?', 'Which statement best reflects Other CABG indications from this note?', '[{"id": "a", "text": "CABG is contraindicated after failed PCI in this note."}, {"id": "b", "text": "Diabetic multivessel CAD always avoids surgery in this note."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "CABG is indicated for failed PCI and in diabetic patients with multivessel CAD."}]'::jsonb, '["d"]'::jsonb, 'Correct because CABG is indicated for failed PCI and in diabetic patients with multivessel CAD. Recognize scenarios where surgery outperforms repeat catheter interventions.', 'CABG and PCI - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Post-CABG airway care in this revascularization scenario?', 'Which finding most strongly supports Post-CABG airway care in this revascularization scenario?', '[{"id": "a", "text": "This pattern is more consistent with Tamponade vigilance."}, {"id": "b", "text": "Respiratory optimization reduces post-op pulmonary complications."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "ABGs are irrelevant post-CABG in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Post-op patient is initially intubated, extubated when stable; monitor ABGs and use incentive spirometry/deep breathing to prevent atelectasis. Respiratory optimization reduces post-op pulmonary complications.', 'CABG and PCI - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches Chest tube threshold?', 'The nurse reviews post-procedure data; which interpretation best matches Chest tube threshold?', '[{"id": "a", "text": "Chest tube output trends are unimportant in this note."}, {"id": "b", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "c", "text": "Chest tube output greater than 100 mL/hr for 2+ hours suggests hemorrhage and requires provider notification."}, {"id": "d", "text": "500 mL/hr output is expected and ignored in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Chest tube output greater than 100 mL/hr for 2+ hours suggests hemorrhage and requires provider notification. Treat persistent high drainage as possible active bleeding emergency.', 'CABG and PCI - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Chest tube handling?', 'Which clinical judgment is most accurate regarding Chest tube handling?', '[{"id": "a", "text": "Tube removal is based only on patient request in this note."}, {"id": "b", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "c", "text": "Maintain drainage patency and monitor for removal readiness safely."}, {"id": "d", "text": "This pattern is more consistent with Other sternal precautions."}]'::jsonb, '["c"]'::jsonb, 'Correct because Chest tubes should remain dependent without kinks and may be removed when output drops below 25–50 mL per shift. Maintain drainage patency and monitor for removal readiness safely.', 'CABG and PCI - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Post-CABG arrhythmia?', 'In urgent triage, which conclusion aligns with Post-CABG arrhythmia?', '[{"id": "a", "text": "This pattern is more consistent with Sternal wound red flags."}, {"id": "b", "text": "Atrial fibrillation is the most common arrhythmia after CABG, typically on post-op days 2–4."}, {"id": "c", "text": "V-fib is listed most common post-CABG rhythm in this note."}, {"id": "d", "text": "Arrhythmias occur only immediately in OR in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Atrial fibrillation is the most common arrhythmia after CABG, typically on post-op days 2–4. Heighten rhythm surveillance during peak AF window.', 'CABG and PCI - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Tamponade vigilance from this note?', 'Which statement best reflects Tamponade vigilance from this note?', '[{"id": "a", "text": "Tamponade risk is absent after CABG in this note."}, {"id": "b", "text": "Low-pressure triad signs require immediate escalation after cardiac surgery."}, {"id": "c", "text": "MAP target under 40 is acceptable in this note."}, {"id": "d", "text": "Frequent reassessment can be delayed when initial vitals are stable."}]'::jsonb, '["b"]'::jsonb, 'Correct because Post-CABG priorities include monitoring for tamponade using Beck''s triad and maintaining MAP at least 65. Low-pressure triad signs require immediate escalation after cardiac surgery.', 'CABG and PCI - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Sternal precautions lifting in this revascularization scenario?', 'Which finding most strongly supports Sternal precautions lifting in this revascularization scenario?', '[{"id": "a", "text": "Heavy lifting accelerates healing in this note."}, {"id": "b", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "c", "text": "Sternal precautions include no lifting over 5–10 pounds for 6–8 weeks."}, {"id": "d", "text": "No lifting restrictions exist post-CABG in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Sternal precautions include no lifting over 5–10 pounds for 6–8 weeks. Protect sternal healing and prevent dehiscence.', 'CABG and PCI - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches Other sternal precautions?', 'The nurse reviews post-procedure data; which interpretation best matches Other sternal precautions?', '[{"id": "a", "text": "This pattern is more consistent with CAD progression."}, {"id": "b", "text": "Coughing should avoid splint support in this note."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "Teach movement restrictions clearly before discharge."}]'::jsonb, '["d"]'::jsonb, 'Correct because No heavy pushing/pulling, no driving 4–6 weeks, and splint sternum with pillow when coughing/sneezing. Teach movement restrictions clearly before discharge.', 'CABG and PCI - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Sternal wound red flags?', 'Which clinical judgment is most accurate regarding Sternal wound red flags?', '[{"id": "a", "text": "Sternal clicking indicates normal healing in this note."}, {"id": "b", "text": "Patients should report sternal clicking, drainage, fever, or increasing redness."}, {"id": "c", "text": "This pattern is more consistent with Revascularization options."}, {"id": "d", "text": "Frequent reassessment can be delayed when initial vitals are stable."}]'::jsonb, '["b"]'::jsonb, 'Correct because Patients should report sternal clicking, drainage, fever, or increasing redness. Early infection/dehiscence signs require prompt evaluation.', 'CABG and PCI - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with PCI vs CABG outcomes summary?', 'In urgent triage, which conclusion aligns with PCI vs CABG outcomes summary?', '[{"id": "a", "text": "This pattern is more consistent with PCI basics."}, {"id": "b", "text": "CABG is first choice for all simple 1-vessel lesions in this note."}, {"id": "c", "text": "PCI recovery is listed longer than CABG in this note."}, {"id": "d", "text": "Balance invasiveness and durability against anatomy and comorbidity burden."}]'::jsonb, '["d"]'::jsonb, 'Correct because PCI has shorter recovery and suits selected 1–2 vessel/STEMI/high-surgical-risk cases; CABG has longer recovery and suits left main/multivessel/DM/low EF. Balance invasiveness and durability against anatomy and comorbidity burden.', 'CABG and PCI - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects NCLEX priority synthesis from this note?', 'Which statement best reflects NCLEX priority synthesis from this note?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "c", "text": "NCLEX priorities emphasize post-CABG tamponade assessment, strict sternal precautions, and post-PCI DAPT compliance."}, {"id": "d", "text": "This pattern is more consistent with Drug-eluting stent role."}]'::jsonb, '["c"]'::jsonb, 'Correct because NCLEX priorities emphasize post-CABG tamponade assessment, strict sternal precautions, and post-PCI DAPT compliance. Focus teaching and monitoring on highest-risk preventable complications.', 'CABG and PCI - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports CAD progression in this revascularization scenario?', 'Which finding most strongly supports CAD progression in this revascularization scenario?', '[{"id": "a", "text": "STEMI is earliest stage in this note."}, {"id": "b", "text": "This pattern is more consistent with Primary PCI timing."}, {"id": "c", "text": "Escalating symptoms should trigger faster revascularization decisions."}, {"id": "d", "text": "CAD progression ends at stable angina in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because CAD progression listed is stable angina to unstable angina to NSTEMI to STEMI. Escalating symptoms should trigger faster revascularization decisions.', 'CABG and PCI - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches Revascularization options?', 'The nurse reviews post-procedure data; which interpretation best matches Revascularization options?', '[{"id": "a", "text": "This pattern is more consistent with PCI indications."}, {"id": "b", "text": "PCI and CABG are interchangeable regardless anatomy in this note."}, {"id": "c", "text": "Two options are PCI (less invasive) and CABG (surgery), selected by vessel count, anatomy, EF, and comorbidities."}, {"id": "d", "text": "Post-procedure education has minimal impact on outcomes."}]'::jsonb, '["c"]'::jsonb, 'Correct because Two options are PCI (less invasive) and CABG (surgery), selected by vessel count, anatomy, EF, and comorbidities. Procedure choice must match anatomy and risk profile, not convenience.', 'CABG and PCI - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding PCI basics?', 'Which clinical judgment is most accurate regarding PCI basics?', '[{"id": "a", "text": "Monitor access-site and reperfusion outcomes immediately post-procedure."}, {"id": "b", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "c", "text": "PCI never uses stents in this note."}, {"id": "d", "text": "PCI is open-heart surgery in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because PCI is catheter-based via radial or femoral access, using balloon angioplasty and often stent placement. Monitor access-site and reperfusion outcomes immediately post-procedure.', 'CABG and PCI - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Drug-eluting stent role?', 'In urgent triage, which conclusion aligns with Drug-eluting stent role?', '[{"id": "a", "text": "This pattern is more consistent with Post-PCI vitals and site care."}, {"id": "b", "text": "Drug-eluting stents contain antiproliferative medication to reduce restenosis."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "DES increases restenosis intentionally in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Drug-eluting stents contain antiproliferative medication to reduce restenosis. Maintain antiplatelet adherence to prevent stent thrombosis/restenosis.', 'CABG and PCI - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Primary PCI timing from this note?', 'Which statement best reflects Primary PCI timing from this note?', '[{"id": "a", "text": "Time-to-balloon directly impacts myocardial salvage."}, {"id": "b", "text": "Primary PCI target is 24 hours in this note."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Primary PCI is not used for STEMI in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Primary PCI is treatment of choice for STEMI with door-to-balloon goal within 90 minutes. Time-to-balloon directly impacts myocardial salvage.', 'CABG and PCI - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports PCI indications in this revascularization scenario?', 'Which finding most strongly supports PCI indications in this revascularization scenario?', '[{"id": "a", "text": "PCI is contraindicated in all acute MI in this note."}, {"id": "b", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "PCI indications include STEMI/NSTEMI, refractory unstable angina, suitable 1–2 vessel disease, or high CABG surgical risk."}]'::jsonb, '["d"]'::jsonb, 'Correct because PCI indications include STEMI/NSTEMI, refractory unstable angina, suitable 1–2 vessel disease, or high CABG surgical risk. Use PCI when anatomy and risk profile make catheter strategy appropriate.', 'CABG and PCI - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches Pre-PCI preparation?', 'The nurse reviews post-procedure data; which interpretation best matches Pre-PCI preparation?', '[{"id": "a", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "b", "text": "Pulse baseline is not needed in this note."}, {"id": "c", "text": "This pattern is more consistent with PCI complications."}, {"id": "d", "text": "Optimize safety by preparing bleeding, renal, and access monitoring plans."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pre-PCI care includes NPO 4–6 hours, IV access, type and screen, DAPT initiation, anticoagulation, creatinine check, and pulse marking. Optimize safety by preparing bleeding, renal, and access monitoring plans.', 'CABG and PCI - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Post-PCI vitals and site care?', 'Which clinical judgment is most accurate regarding Post-PCI vitals and site care?', '[{"id": "a", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "b", "text": "Post-PCI protocol includes frequent vitals and puncture site checks for bleeding/hematoma."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "Site checks are unnecessary after sheath removal in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Post-PCI protocol includes frequent vitals and puncture site checks for bleeding/hematoma. Early detection of access complications prevents deterioration.', 'CABG and PCI - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Post-PCI limb and hydration?', 'In urgent triage, which conclusion aligns with Post-PCI limb and hydration?', '[{"id": "a", "text": "Protect access integrity while lowering nephropathy risk."}, {"id": "b", "text": "This pattern is more consistent with CABG graft options."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Frequent reassessment can be delayed when initial vitals are stable."}]'::jsonb, '["a"]'::jsonb, 'Correct because Femoral approach requires limb straight with bedrest 4–6 hours; fluids are encouraged to clear contrast. Protect access integrity while lowering nephropathy risk.', 'CABG and PCI - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Post-PCI medication adherence from this note?', 'Which statement best reflects Post-PCI medication adherence from this note?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "c", "text": "Dual antiplatelet therapy is required for at least 1 year after stent placement."}, {"id": "d", "text": "DAPT stops after 48 hours in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Dual antiplatelet therapy is required for at least 1 year after stent placement. Nonadherence significantly raises stent thrombosis risk.', 'CABG and PCI - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports PCI complications in this revascularization scenario?', 'Which finding most strongly supports PCI complications in this revascularization scenario?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "Monitor for ischemic recurrence and bleeding/renal complications continuously."}, {"id": "c", "text": "Restenosis is impossible with stents in this note."}, {"id": "d", "text": "This pattern is more consistent with Other CABG indications."}]'::jsonb, '["b"]'::jsonb, 'Correct because Listed PCI complications include access-site bleeding (most common), contrast nephropathy, arterial dissection, restenosis/re-occlusion, and stent thrombosis. Monitor for ischemic recurrence and bleeding/renal complications continuously.', 'CABG and PCI - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches CABG definition?', 'The nurse reviews post-procedure data; which interpretation best matches CABG definition?', '[{"id": "a", "text": "CABG is open-heart bypass surgery using grafts to route blood around blocked coronaries."}, {"id": "b", "text": "This pattern is more consistent with Post-CABG airway care."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "Post-procedure education has minimal impact on outcomes."}]'::jsonb, '["a"]'::jsonb, 'Correct because CABG is open-heart bypass surgery using grafts to route blood around blocked coronaries. Post-op priorities focus on airway, hemodynamics, and graft-related complications.', 'CABG and PCI - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding CABG graft options?', 'Which clinical judgment is most accurate regarding CABG graft options?', '[{"id": "a", "text": "Only synthetic grafts are used in this note."}, {"id": "b", "text": "Understand graft source/patency differences for long-term follow-up education."}, {"id": "c", "text": "Internal mammary graft is never connected to LAD in this note."}, {"id": "d", "text": "This pattern is more consistent with Chest tube threshold."}]'::jsonb, '["b"]'::jsonb, 'Correct because Graft choices include reversed saphenous vein, internal mammary artery (most durable to LAD), and radial artery. Understand graft source/patency differences for long-term follow-up education.', 'CABG and PCI - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with CABG indications high risk anatomy?', 'In urgent triage, which conclusion aligns with CABG indications high risk anatomy?', '[{"id": "a", "text": "CABG indications include left main disease >50%, 3-vessel CAD especially with reduced EF, and proximal LAD involvement."}, {"id": "b", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "c", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "d", "text": "Left main stenosis is managed only with lifestyle in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because CABG indications include left main disease >50%, 3-vessel CAD especially with reduced EF, and proximal LAD involvement. Escalate to surgical strategy for high-risk multivessel anatomy.', 'CABG and PCI - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Other CABG indications from this note?', 'Which statement best reflects Other CABG indications from this note?', '[{"id": "a", "text": "This pattern is more consistent with Post-CABG arrhythmia."}, {"id": "b", "text": "Recognize scenarios where surgery outperforms repeat catheter interventions."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Frequent reassessment can be delayed when initial vitals are stable."}]'::jsonb, '["b"]'::jsonb, 'Correct because CABG is indicated for failed PCI and in diabetic patients with multivessel CAD. Recognize scenarios where surgery outperforms repeat catheter interventions.', 'CABG and PCI - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Post-CABG airway care in this revascularization scenario?', 'Which finding most strongly supports Post-CABG airway care in this revascularization scenario?', '[{"id": "a", "text": "Post-op patient is initially intubated, extubated when stable; monitor ABGs and use incentive spirometry/deep breathing to prevent atelectasis."}, {"id": "b", "text": "ABGs are irrelevant post-CABG in this note."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Pulmonary exercises are avoided after CABG in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Post-op patient is initially intubated, extubated when stable; monitor ABGs and use incentive spirometry/deep breathing to prevent atelectasis. Respiratory optimization reduces post-op pulmonary complications.', 'CABG and PCI - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches Chest tube threshold?', 'The nurse reviews post-procedure data; which interpretation best matches Chest tube threshold?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "c", "text": "500 mL/hr output is expected and ignored in this note."}, {"id": "d", "text": "Treat persistent high drainage as possible active bleeding emergency."}]'::jsonb, '["d"]'::jsonb, 'Correct because Chest tube output greater than 100 mL/hr for 2+ hours suggests hemorrhage and requires provider notification. Treat persistent high drainage as possible active bleeding emergency.', 'CABG and PCI - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Chest tube handling?', 'Which clinical judgment is most accurate regarding Chest tube handling?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "Chest tubes should remain dependent without kinks and may be removed when output drops below 25–50 mL per shift."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Tube removal is based only on patient request in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Chest tubes should remain dependent without kinks and may be removed when output drops below 25–50 mL per shift. Maintain drainage patency and monitor for removal readiness safely.', 'CABG and PCI - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Post-CABG arrhythmia?', 'In urgent triage, which conclusion aligns with Post-CABG arrhythmia?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "V-fib is listed most common post-CABG rhythm in this note."}, {"id": "c", "text": "Heighten rhythm surveillance during peak AF window."}, {"id": "d", "text": "Post-procedure education has minimal impact on outcomes."}]'::jsonb, '["c"]'::jsonb, 'Correct because Atrial fibrillation is the most common arrhythmia after CABG, typically on post-op days 2–4. Heighten rhythm surveillance during peak AF window.', 'CABG and PCI - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Tamponade vigilance from this note?', 'Which statement best reflects Tamponade vigilance from this note?', '[{"id": "a", "text": "MAP target under 40 is acceptable in this note."}, {"id": "b", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "c", "text": "Post-CABG priorities include monitoring for tamponade using Beck''s triad and maintaining MAP at least 65."}, {"id": "d", "text": "Tamponade risk is absent after CABG in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Post-CABG priorities include monitoring for tamponade using Beck''s triad and maintaining MAP at least 65. Low-pressure triad signs require immediate escalation after cardiac surgery.', 'CABG and PCI - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Sternal precautions lifting in this revascularization scenario?', 'Which finding most strongly supports Sternal precautions lifting in this revascularization scenario?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "Protect sternal healing and prevent dehiscence."}, {"id": "c", "text": "Heavy lifting accelerates healing in this note."}, {"id": "d", "text": "Post-procedure education has minimal impact on outcomes."}]'::jsonb, '["b"]'::jsonb, 'Correct because Sternal precautions include no lifting over 5–10 pounds for 6–8 weeks. Protect sternal healing and prevent dehiscence.', 'CABG and PCI - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews post-procedure data; which interpretation best matches Other sternal precautions?', 'The nurse reviews post-procedure data; which interpretation best matches Other sternal precautions?', '[{"id": "a", "text": "Unrestricted driving starts day after surgery in this note."}, {"id": "b", "text": "Coughing should avoid splint support in this note."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "No heavy pushing/pulling, no driving 4–6 weeks, and splint sternum with pillow when coughing/sneezing."}]'::jsonb, '["d"]'::jsonb, 'Correct because No heavy pushing/pulling, no driving 4–6 weeks, and splint sternum with pillow when coughing/sneezing. Teach movement restrictions clearly before discharge.', 'CABG and PCI - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Sternal wound red flags?', 'Which clinical judgment is most accurate regarding Sternal wound red flags?', '[{"id": "a", "text": "Sternal clicking indicates normal healing in this note."}, {"id": "b", "text": "Redness and fever are expected, no report needed in this note."}, {"id": "c", "text": "Early infection/dehiscence signs require prompt evaluation."}, {"id": "d", "text": "Post-procedure education has minimal impact on outcomes."}]'::jsonb, '["c"]'::jsonb, 'Correct because Patients should report sternal clicking, drainage, fever, or increasing redness. Early infection/dehiscence signs require prompt evaluation.', 'CABG and PCI - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with PCI vs CABG outcomes summary?', 'In urgent triage, which conclusion aligns with PCI vs CABG outcomes summary?', '[{"id": "a", "text": "Frequent reassessment can be delayed when initial vitals are stable."}, {"id": "b", "text": "This pattern is more consistent with PCI basics."}, {"id": "c", "text": "CABG is first choice for all simple 1-vessel lesions in this note."}, {"id": "d", "text": "PCI has shorter recovery and suits selected 1–2 vessel/STEMI/high-surgical-risk cases; CABG has longer recovery and suits left main/multivessel/DM/low EF."}]'::jsonb, '["d"]'::jsonb, 'Correct because PCI has shorter recovery and suits selected 1–2 vessel/STEMI/high-surgical-risk cases; CABG has longer recovery and suits left main/multivessel/DM/low EF. Balance invasiveness and durability against anatomy and comorbidity burden.', 'CABG and PCI - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects NCLEX priority synthesis from this note?', 'Which statement best reflects NCLEX priority synthesis from this note?', '[{"id": "a", "text": "This pattern is more consistent with Drug-eluting stent role."}, {"id": "b", "text": "Tamponade surveillance is not needed after CABG in this note."}, {"id": "c", "text": "Post-procedure education has minimal impact on outcomes."}, {"id": "d", "text": "Focus teaching and monitoring on highest-risk preventable complications."}]'::jsonb, '["d"]'::jsonb, 'Correct because NCLEX priorities emphasize post-CABG tamponade assessment, strict sternal precautions, and post-PCI DAPT compliance. Focus teaching and monitoring on highest-risk preventable complications.', 'CABG and PCI - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for CAD progression. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for CAD progression. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "STEMI is earliest stage in this note."}, {"id": "b", "text": "Stable angina appears before unstable in progression."}, {"id": "c", "text": "NSTEMI and STEMI are later stages."}, {"id": "d", "text": "Progression reflects worsening myocardial perfusion."}, {"id": "e", "text": "CAD progression ends at stable angina in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: CAD progression listed is stable angina to unstable angina to NSTEMI to STEMI.', 'CABG and PCI - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Revascularization options, which statements are correct? (Select all that apply)', 'For care involving Revascularization options, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "EF is irrelevant to decision in this note."}, {"id": "b", "text": "PCI is less invasive option."}, {"id": "c", "text": "PCI and CABG are interchangeable regardless anatomy in this note."}, {"id": "d", "text": "Selection factors include vessels/anatomy/EF/comorbidities."}, {"id": "e", "text": "CABG is surgical option."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Two options are PCI (less invasive) and CABG (surgery), selected by vessel count, anatomy, EF, and comorbidities.', 'CABG and PCI - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around PCI basics. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around PCI basics. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Balloon compresses plaque."}, {"id": "b", "text": "PCI is open-heart surgery in this note."}, {"id": "c", "text": "Radial and femoral access are listed."}, {"id": "d", "text": "PCI never uses stents in this note."}, {"id": "e", "text": "Stent scaffold may be left in artery."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: PCI is catheter-based via radial or femoral access, using balloon angioplasty and often stent placement.', 'CABG and PCI - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Drug-eluting stent role? (Select all that apply)', 'During reassessment, which observations support Drug-eluting stent role? (Select all that apply)', '[{"id": "a", "text": "DES removes need for any antiplatelet therapy in this note."}, {"id": "b", "text": "DES aims to lower restenosis risk."}, {"id": "c", "text": "Stent choice affects post-procedure management."}, {"id": "d", "text": "DES has antiproliferative coating."}, {"id": "e", "text": "DES increases restenosis intentionally in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Drug-eluting stents contain antiproliferative medication to reduce restenosis.', 'CABG and PCI - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Primary PCI timing in this note? (Select all that apply)', 'Which cues are consistent with Primary PCI timing in this note? (Select all that apply)', '[{"id": "a", "text": "Rapid activation is essential."}, {"id": "b", "text": "STEMI door-to-balloon target is 90 min."}, {"id": "c", "text": "Primary PCI is preferred STEMI reperfusion strategy."}, {"id": "d", "text": "Primary PCI target is 24 hours in this note."}, {"id": "e", "text": "Primary PCI is not used for STEMI in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Primary PCI is treatment of choice for STEMI with door-to-balloon goal within 90 minutes.', 'CABG and PCI - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for PCI indications. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for PCI indications. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "1–2 vessel suitable anatomy is listed indication."}, {"id": "b", "text": "Left main multivessel disease is always first-choice PCI in this note."}, {"id": "c", "text": "Refractory unstable angina is listed indication."}, {"id": "d", "text": "STEMI and NSTEMI are listed indications."}, {"id": "e", "text": "PCI is contraindicated in all acute MI in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: PCI indications include STEMI/NSTEMI, refractory unstable angina, suitable 1–2 vessel disease, or high CABG surgical risk.', 'CABG and PCI - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Pre-PCI preparation, which statements are correct? (Select all that apply)', 'For care involving Pre-PCI preparation, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pulse baseline is not needed in this note."}, {"id": "b", "text": "Renal function check is unnecessary pre-PCI in this note."}, {"id": "c", "text": "Creatinine check is listed for contrast risk."}, {"id": "d", "text": "Pedal pulses are assessed/marked pre-procedure."}, {"id": "e", "text": "NPO 4–6 hours is listed."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pre-PCI care includes NPO 4–6 hours, IV access, type and screen, DAPT initiation, anticoagulation, creatinine check, and pulse marking.', 'CABG and PCI - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Post-PCI vitals and site care. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Post-PCI vitals and site care. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Vitals can be deferred for several hours in this note."}, {"id": "b", "text": "Bleeding/hematoma monitoring is required."}, {"id": "c", "text": "Access-site surveillance is key post-PCI."}, {"id": "d", "text": "Site checks are unnecessary after sheath removal in this note."}, {"id": "e", "text": "Frequent scheduled vitals are listed."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Post-PCI protocol includes frequent vitals and puncture site checks for bleeding/hematoma.', 'CABG and PCI - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Post-PCI limb and hydration? (Select all that apply)', 'During reassessment, which observations support Post-PCI limb and hydration? (Select all that apply)', '[{"id": "a", "text": "Hydration is encouraged to flush contrast."}, {"id": "b", "text": "Fluid restriction is mandatory after contrast in this note."}, {"id": "c", "text": "Immediate vigorous leg flexion is recommended in this note."}, {"id": "d", "text": "Bedrest 4–6 hours listed for femoral access."}, {"id": "e", "text": "Affected femoral limb kept straight post-procedure."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Femoral approach requires limb straight with bedrest 4–6 hours; fluids are encouraged to clear contrast.', 'CABG and PCI - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Post-PCI medication adherence in this note? (Select all that apply)', 'Which cues are consistent with Post-PCI medication adherence in this note? (Select all that apply)', '[{"id": "a", "text": "Aspirin alone is immediate replacement for all stent patients in this note."}, {"id": "b", "text": "Medication adherence is critical after stent."}, {"id": "c", "text": "DAPT minimum one year is listed."}, {"id": "d", "text": "Aspirin + P2Y12 strategy is emphasized."}, {"id": "e", "text": "DAPT stops after 48 hours in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Dual antiplatelet therapy is required for at least 1 year after stent placement.', 'CABG and PCI - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for PCI complications. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for PCI complications. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Stent thrombosis is emergency complication."}, {"id": "b", "text": "PCI has no renal complications in this note."}, {"id": "c", "text": "Restenosis is impossible with stents in this note."}, {"id": "d", "text": "Contrast nephropathy is listed."}, {"id": "e", "text": "Bleeding at access site is most common complication listed."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Listed PCI complications include access-site bleeding (most common), contrast nephropathy, arterial dissection, restenosis/re-occlusion, and stent thrombosis.', 'CABG and PCI - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving CABG definition, which statements are correct? (Select all that apply)', 'For care involving CABG definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Bypass grafts reroute flow around blockage."}, {"id": "b", "text": "CABG avoids any graft vessel use in this note."}, {"id": "c", "text": "CABG is open-heart surgery in note."}, {"id": "d", "text": "CABG is a bedside catheter procedure in this note."}, {"id": "e", "text": "CABG is revascularization option for complex CAD."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: CABG is open-heart bypass surgery using grafts to route blood around blocked coronaries.', 'CABG and PCI - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around CABG graft options. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around CABG graft options. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Internal mammary graft is never connected to LAD in this note."}, {"id": "b", "text": "Radial artery can be used."}, {"id": "c", "text": "Saphenous vein graft is listed."}, {"id": "d", "text": "Only synthetic grafts are used in this note."}, {"id": "e", "text": "LIMA-to-LAD is highlighted as durable."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Graft choices include reversed saphenous vein, internal mammary artery (most durable to LAD), and radial artery.', 'CABG and PCI - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support CABG indications high risk anatomy? (Select all that apply)', 'During reassessment, which observations support CABG indications high risk anatomy? (Select all that apply)', '[{"id": "a", "text": "Proximal LAD involvement in 2-vessel disease listed indication."}, {"id": "b", "text": "Single-vessel mild disease always requires CABG in this note."}, {"id": "c", "text": "Left main stenosis is managed only with lifestyle in this note."}, {"id": "d", "text": "3-vessel with low EF favors CABG."}, {"id": "e", "text": "Left main >50% is listed indication."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: CABG indications include left main disease >50%, 3-vessel CAD especially with reduced EF, and proximal LAD involvement.', 'CABG and PCI - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Other CABG indications in this note? (Select all that apply)', 'Which cues are consistent with Other CABG indications in this note? (Select all that apply)', '[{"id": "a", "text": "CABG can be chosen when PCI strategy insufficient."}, {"id": "b", "text": "Diabetic multivessel CAD always avoids surgery in this note."}, {"id": "c", "text": "Failed PCI is listed CABG indication."}, {"id": "d", "text": "Diabetes with multivessel CAD is listed indication."}, {"id": "e", "text": "CABG is contraindicated after failed PCI in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: CABG is indicated for failed PCI and in diabetic patients with multivessel CAD.', 'CABG and PCI - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Post-CABG airway care. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Post-CABG airway care. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Initial intubation then extubation when ready is listed."}, {"id": "b", "text": "Incentive spirometry/deep breathing are listed."}, {"id": "c", "text": "Pulmonary exercises are avoided after CABG in this note."}, {"id": "d", "text": "ABGs are irrelevant post-CABG in this note."}, {"id": "e", "text": "ABG monitoring is listed."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Post-op patient is initially intubated, extubated when stable; monitor ABGs and use incentive spirometry/deep breathing to prevent atelectasis.', 'CABG and PCI - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Chest tube threshold, which statements are correct? (Select all that apply)', 'For care involving Chest tube threshold, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Chest tube output trends are unimportant in this note."}, {"id": "b", "text": ">100 mL/hr for 2+ hr threshold is listed."}, {"id": "c", "text": "500 mL/hr output is expected and ignored in this note."}, {"id": "d", "text": "High output indicates possible hemorrhage."}, {"id": "e", "text": "Escalation/notification is required."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Chest tube output greater than 100 mL/hr for 2+ hours suggests hemorrhage and requires provider notification.', 'CABG and PCI - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Chest tube handling. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Chest tube handling. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Tube removal is based only on patient request in this note."}, {"id": "b", "text": "Avoid kinks in tubing is listed."}, {"id": "c", "text": "Removal threshold <25–50 mL/shift is listed."}, {"id": "d", "text": "Clamp chest tubes routinely to test patency in this note."}, {"id": "e", "text": "Dependent tubing is emphasized."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Chest tubes should remain dependent without kinks and may be removed when output drops below 25–50 mL per shift.', 'CABG and PCI - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Post-CABG arrhythmia? (Select all that apply)', 'During reassessment, which observations support Post-CABG arrhythmia? (Select all that apply)', '[{"id": "a", "text": "Continuous monitoring is needed."}, {"id": "b", "text": "Arrhythmias occur only immediately in OR in this note."}, {"id": "c", "text": "AF is most common post-CABG arrhythmia."}, {"id": "d", "text": "V-fib is listed most common post-CABG rhythm in this note."}, {"id": "e", "text": "Peak timing days 2–4 is listed."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Atrial fibrillation is the most common arrhythmia after CABG, typically on post-op days 2–4.', 'CABG and PCI - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Tamponade vigilance in this note? (Select all that apply)', 'Which cues are consistent with Tamponade vigilance in this note? (Select all that apply)', '[{"id": "a", "text": "Tamponade risk is absent after CABG in this note."}, {"id": "b", "text": "MAP ≥65 target is listed."}, {"id": "c", "text": "MAP target under 40 is acceptable in this note."}, {"id": "d", "text": "Beck''s triad monitoring is listed post-CABG."}, {"id": "e", "text": "Hemodynamic deterioration can indicate tamponade."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Post-CABG priorities include monitoring for tamponade using Beck''s triad and maintaining MAP at least 65.', 'CABG and PCI - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Sternal precautions lifting. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Sternal precautions lifting. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Restriction duration 6–8 weeks is listed."}, {"id": "b", "text": "Heavy lifting accelerates healing in this note."}, {"id": "c", "text": "Precaution supports sternal healing."}, {"id": "d", "text": "Lifting limit 5–10 lb is listed."}, {"id": "e", "text": "No lifting restrictions exist post-CABG in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Sternal precautions include no lifting over 5–10 pounds for 6–8 weeks.', 'CABG and PCI - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Other sternal precautions, which statements are correct? (Select all that apply)', 'For care involving Other sternal precautions, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Coughing should avoid splint support in this note."}, {"id": "b", "text": "Heavy push/pull restriction is listed."}, {"id": "c", "text": "No driving 4–6 weeks is listed."}, {"id": "d", "text": "Pillow splinting when coughing is listed."}, {"id": "e", "text": "Unrestricted driving starts day after surgery in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: No heavy pushing/pulling, no driving 4–6 weeks, and splint sternum with pillow when coughing/sneezing.', 'CABG and PCI - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Sternal wound red flags. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Sternal wound red flags. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Redness and fever are expected, no report needed in this note."}, {"id": "b", "text": "Drainage/fever/redness are warning signs."}, {"id": "c", "text": "Prompt reporting is part of discharge teaching."}, {"id": "d", "text": "Sternal clicking is warning sign."}, {"id": "e", "text": "Sternal clicking indicates normal healing in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Patients should report sternal clicking, drainage, fever, or increasing redness.', 'CABG and PCI - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support PCI vs CABG outcomes summary? (Select all that apply)', 'During reassessment, which observations support PCI vs CABG outcomes summary? (Select all that apply)', '[{"id": "a", "text": "Procedure selection differs by disease complexity."}, {"id": "b", "text": "CABG is first choice for all simple 1-vessel lesions in this note."}, {"id": "c", "text": "CABG preferred for left main/3-vessel/DM/low EF patterns."}, {"id": "d", "text": "PCI recovery is faster in comparison table."}, {"id": "e", "text": "PCI recovery is listed longer than CABG in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: PCI has shorter recovery and suits selected 1–2 vessel/STEMI/high-surgical-risk cases; CABG has longer recovery and suits left main/multivessel/DM/low EF.', 'CABG and PCI - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with NCLEX priority synthesis in this note? (Select all that apply)', 'Which cues are consistent with NCLEX priority synthesis in this note? (Select all that apply)', '[{"id": "a", "text": "Sternal precautions are highlighted NCLEX priority."}, {"id": "b", "text": "DAPT adherence post-PCI is highlighted NCLEX priority."}, {"id": "c", "text": "Tamponade surveillance is not needed after CABG in this note."}, {"id": "d", "text": "Tamponade assessment is highlighted NCLEX priority."}, {"id": "e", "text": "Medication adherence is optional after stent in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: NCLEX priorities emphasize post-CABG tamponade assessment, strict sternal precautions, and post-PCI DAPT compliance.', 'CABG and PCI - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for CAD progression. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for CAD progression. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "STEMI is earliest stage in this note."}, {"id": "b", "text": "CAD progression ends at stable angina in this note."}, {"id": "c", "text": "Progression reflects worsening myocardial perfusion."}, {"id": "d", "text": "Stable angina appears before unstable in progression."}, {"id": "e", "text": "NSTEMI and STEMI are later stages."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: CAD progression listed is stable angina to unstable angina to NSTEMI to STEMI.', 'CABG and PCI - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Revascularization options, which statements are correct? (Select all that apply)', 'For care involving Revascularization options, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "PCI and CABG are interchangeable regardless anatomy in this note."}, {"id": "b", "text": "PCI is less invasive option."}, {"id": "c", "text": "Selection factors include vessels/anatomy/EF/comorbidities."}, {"id": "d", "text": "CABG is surgical option."}, {"id": "e", "text": "EF is irrelevant to decision in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Two options are PCI (less invasive) and CABG (surgery), selected by vessel count, anatomy, EF, and comorbidities.', 'CABG and PCI - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around PCI basics. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around PCI basics. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Radial and femoral access are listed."}, {"id": "b", "text": "PCI is open-heart surgery in this note."}, {"id": "c", "text": "PCI never uses stents in this note."}, {"id": "d", "text": "Stent scaffold may be left in artery."}, {"id": "e", "text": "Balloon compresses plaque."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: PCI is catheter-based via radial or femoral access, using balloon angioplasty and often stent placement.', 'CABG and PCI - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Drug-eluting stent role? (Select all that apply)', 'During reassessment, which observations support Drug-eluting stent role? (Select all that apply)', '[{"id": "a", "text": "DES removes need for any antiplatelet therapy in this note."}, {"id": "b", "text": "DES aims to lower restenosis risk."}, {"id": "c", "text": "Stent choice affects post-procedure management."}, {"id": "d", "text": "DES has antiproliferative coating."}, {"id": "e", "text": "DES increases restenosis intentionally in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Drug-eluting stents contain antiproliferative medication to reduce restenosis.', 'CABG and PCI - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Primary PCI timing in this note? (Select all that apply)', 'Which cues are consistent with Primary PCI timing in this note? (Select all that apply)', '[{"id": "a", "text": "Primary PCI target is 24 hours in this note."}, {"id": "b", "text": "STEMI door-to-balloon target is 90 min."}, {"id": "c", "text": "Primary PCI is not used for STEMI in this note."}, {"id": "d", "text": "Primary PCI is preferred STEMI reperfusion strategy."}, {"id": "e", "text": "Rapid activation is essential."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Primary PCI is treatment of choice for STEMI with door-to-balloon goal within 90 minutes.', 'CABG and PCI - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for PCI indications. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for PCI indications. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Left main multivessel disease is always first-choice PCI in this note."}, {"id": "b", "text": "1–2 vessel suitable anatomy is listed indication."}, {"id": "c", "text": "STEMI and NSTEMI are listed indications."}, {"id": "d", "text": "Refractory unstable angina is listed indication."}, {"id": "e", "text": "PCI is contraindicated in all acute MI in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: PCI indications include STEMI/NSTEMI, refractory unstable angina, suitable 1–2 vessel disease, or high CABG surgical risk.', 'CABG and PCI - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Pre-PCI preparation, which statements are correct? (Select all that apply)', 'For care involving Pre-PCI preparation, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "NPO 4–6 hours is listed."}, {"id": "b", "text": "Pedal pulses are assessed/marked pre-procedure."}, {"id": "c", "text": "Creatinine check is listed for contrast risk."}, {"id": "d", "text": "Renal function check is unnecessary pre-PCI in this note."}, {"id": "e", "text": "Pulse baseline is not needed in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Pre-PCI care includes NPO 4–6 hours, IV access, type and screen, DAPT initiation, anticoagulation, creatinine check, and pulse marking.', 'CABG and PCI - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Post-PCI vitals and site care. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Post-PCI vitals and site care. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Vitals can be deferred for several hours in this note."}, {"id": "b", "text": "Site checks are unnecessary after sheath removal in this note."}, {"id": "c", "text": "Frequent scheduled vitals are listed."}, {"id": "d", "text": "Bleeding/hematoma monitoring is required."}, {"id": "e", "text": "Access-site surveillance is key post-PCI."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Post-PCI protocol includes frequent vitals and puncture site checks for bleeding/hematoma.', 'CABG and PCI - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Post-PCI limb and hydration? (Select all that apply)', 'During reassessment, which observations support Post-PCI limb and hydration? (Select all that apply)', '[{"id": "a", "text": "Bedrest 4–6 hours listed for femoral access."}, {"id": "b", "text": "Fluid restriction is mandatory after contrast in this note."}, {"id": "c", "text": "Affected femoral limb kept straight post-procedure."}, {"id": "d", "text": "Hydration is encouraged to flush contrast."}, {"id": "e", "text": "Immediate vigorous leg flexion is recommended in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Femoral approach requires limb straight with bedrest 4–6 hours; fluids are encouraged to clear contrast.', 'CABG and PCI - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Post-PCI medication adherence in this note? (Select all that apply)', 'Which cues are consistent with Post-PCI medication adherence in this note? (Select all that apply)', '[{"id": "a", "text": "Aspirin alone is immediate replacement for all stent patients in this note."}, {"id": "b", "text": "DAPT stops after 48 hours in this note."}, {"id": "c", "text": "Aspirin + P2Y12 strategy is emphasized."}, {"id": "d", "text": "DAPT minimum one year is listed."}, {"id": "e", "text": "Medication adherence is critical after stent."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Dual antiplatelet therapy is required for at least 1 year after stent placement.', 'CABG and PCI - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for PCI complications. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for PCI complications. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Stent thrombosis is emergency complication."}, {"id": "b", "text": "Restenosis is impossible with stents in this note."}, {"id": "c", "text": "Bleeding at access site is most common complication listed."}, {"id": "d", "text": "PCI has no renal complications in this note."}, {"id": "e", "text": "Contrast nephropathy is listed."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Listed PCI complications include access-site bleeding (most common), contrast nephropathy, arterial dissection, restenosis/re-occlusion, and stent thrombosis.', 'CABG and PCI - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving CABG definition, which statements are correct? (Select all that apply)', 'For care involving CABG definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Bypass grafts reroute flow around blockage."}, {"id": "b", "text": "CABG avoids any graft vessel use in this note."}, {"id": "c", "text": "CABG is open-heart surgery in note."}, {"id": "d", "text": "CABG is revascularization option for complex CAD."}, {"id": "e", "text": "CABG is a bedside catheter procedure in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: CABG is open-heart bypass surgery using grafts to route blood around blocked coronaries.', 'CABG and PCI - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around CABG graft options. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around CABG graft options. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Saphenous vein graft is listed."}, {"id": "b", "text": "Only synthetic grafts are used in this note."}, {"id": "c", "text": "LIMA-to-LAD is highlighted as durable."}, {"id": "d", "text": "Internal mammary graft is never connected to LAD in this note."}, {"id": "e", "text": "Radial artery can be used."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Graft choices include reversed saphenous vein, internal mammary artery (most durable to LAD), and radial artery.', 'CABG and PCI - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support CABG indications high risk anatomy? (Select all that apply)', 'During reassessment, which observations support CABG indications high risk anatomy? (Select all that apply)', '[{"id": "a", "text": "Single-vessel mild disease always requires CABG in this note."}, {"id": "b", "text": "Left main >50% is listed indication."}, {"id": "c", "text": "3-vessel with low EF favors CABG."}, {"id": "d", "text": "Proximal LAD involvement in 2-vessel disease listed indication."}, {"id": "e", "text": "Left main stenosis is managed only with lifestyle in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: CABG indications include left main disease >50%, 3-vessel CAD especially with reduced EF, and proximal LAD involvement.', 'CABG and PCI - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Other CABG indications in this note? (Select all that apply)', 'Which cues are consistent with Other CABG indications in this note? (Select all that apply)', '[{"id": "a", "text": "CABG is contraindicated after failed PCI in this note."}, {"id": "b", "text": "Diabetic multivessel CAD always avoids surgery in this note."}, {"id": "c", "text": "Failed PCI is listed CABG indication."}, {"id": "d", "text": "CABG can be chosen when PCI strategy insufficient."}, {"id": "e", "text": "Diabetes with multivessel CAD is listed indication."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: CABG is indicated for failed PCI and in diabetic patients with multivessel CAD.', 'CABG and PCI - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Post-CABG airway care. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Post-CABG airway care. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "ABGs are irrelevant post-CABG in this note."}, {"id": "b", "text": "Initial intubation then extubation when ready is listed."}, {"id": "c", "text": "Pulmonary exercises are avoided after CABG in this note."}, {"id": "d", "text": "ABG monitoring is listed."}, {"id": "e", "text": "Incentive spirometry/deep breathing are listed."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Post-op patient is initially intubated, extubated when stable; monitor ABGs and use incentive spirometry/deep breathing to prevent atelectasis.', 'CABG and PCI - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Chest tube threshold, which statements are correct? (Select all that apply)', 'For care involving Chest tube threshold, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Chest tube output trends are unimportant in this note."}, {"id": "b", "text": ">100 mL/hr for 2+ hr threshold is listed."}, {"id": "c", "text": "Escalation/notification is required."}, {"id": "d", "text": "500 mL/hr output is expected and ignored in this note."}, {"id": "e", "text": "High output indicates possible hemorrhage."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Chest tube output greater than 100 mL/hr for 2+ hours suggests hemorrhage and requires provider notification.', 'CABG and PCI - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Chest tube handling. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Chest tube handling. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Tube removal is based only on patient request in this note."}, {"id": "b", "text": "Avoid kinks in tubing is listed."}, {"id": "c", "text": "Removal threshold <25–50 mL/shift is listed."}, {"id": "d", "text": "Clamp chest tubes routinely to test patency in this note."}, {"id": "e", "text": "Dependent tubing is emphasized."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Chest tubes should remain dependent without kinks and may be removed when output drops below 25–50 mL per shift.', 'CABG and PCI - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Post-CABG arrhythmia? (Select all that apply)', 'During reassessment, which observations support Post-CABG arrhythmia? (Select all that apply)', '[{"id": "a", "text": "Peak timing days 2–4 is listed."}, {"id": "b", "text": "Continuous monitoring is needed."}, {"id": "c", "text": "V-fib is listed most common post-CABG rhythm in this note."}, {"id": "d", "text": "Arrhythmias occur only immediately in OR in this note."}, {"id": "e", "text": "AF is most common post-CABG arrhythmia."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Atrial fibrillation is the most common arrhythmia after CABG, typically on post-op days 2–4.', 'CABG and PCI - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with Tamponade vigilance in this note? (Select all that apply)', 'Which cues are consistent with Tamponade vigilance in this note? (Select all that apply)', '[{"id": "a", "text": "MAP ≥65 target is listed."}, {"id": "b", "text": "MAP target under 40 is acceptable in this note."}, {"id": "c", "text": "Tamponade risk is absent after CABG in this note."}, {"id": "d", "text": "Beck''s triad monitoring is listed post-CABG."}, {"id": "e", "text": "Hemodynamic deterioration can indicate tamponade."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Post-CABG priorities include monitoring for tamponade using Beck''s triad and maintaining MAP at least 65.', 'CABG and PCI - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Sternal precautions lifting. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Sternal precautions lifting. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Precaution supports sternal healing."}, {"id": "b", "text": "Restriction duration 6–8 weeks is listed."}, {"id": "c", "text": "Lifting limit 5–10 lb is listed."}, {"id": "d", "text": "No lifting restrictions exist post-CABG in this note."}, {"id": "e", "text": "Heavy lifting accelerates healing in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Sternal precautions include no lifting over 5–10 pounds for 6–8 weeks.', 'CABG and PCI - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Other sternal precautions, which statements are correct? (Select all that apply)', 'For care involving Other sternal precautions, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pillow splinting when coughing is listed."}, {"id": "b", "text": "Coughing should avoid splint support in this note."}, {"id": "c", "text": "Unrestricted driving starts day after surgery in this note."}, {"id": "d", "text": "Heavy push/pull restriction is listed."}, {"id": "e", "text": "No driving 4–6 weeks is listed."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: No heavy pushing/pulling, no driving 4–6 weeks, and splint sternum with pillow when coughing/sneezing.', 'CABG and PCI - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions around Sternal wound red flags. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions around Sternal wound red flags. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Prompt reporting is part of discharge teaching."}, {"id": "b", "text": "Drainage/fever/redness are warning signs."}, {"id": "c", "text": "Sternal clicking indicates normal healing in this note."}, {"id": "d", "text": "Sternal clicking is warning sign."}, {"id": "e", "text": "Redness and fever are expected, no report needed in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Patients should report sternal clicking, drainage, fever, or increasing redness.', 'CABG and PCI - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support PCI vs CABG outcomes summary? (Select all that apply)', 'During reassessment, which observations support PCI vs CABG outcomes summary? (Select all that apply)', '[{"id": "a", "text": "PCI recovery is faster in comparison table."}, {"id": "b", "text": "PCI recovery is listed longer than CABG in this note."}, {"id": "c", "text": "Procedure selection differs by disease complexity."}, {"id": "d", "text": "CABG preferred for left main/3-vessel/DM/low EF patterns."}, {"id": "e", "text": "CABG is first choice for all simple 1-vessel lesions in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: PCI has shorter recovery and suits selected 1–2 vessel/STEMI/high-surgical-risk cases; CABG has longer recovery and suits left main/multivessel/DM/low EF.', 'CABG and PCI - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which cues are consistent with NCLEX priority synthesis in this note? (Select all that apply)', 'Which cues are consistent with NCLEX priority synthesis in this note? (Select all that apply)', '[{"id": "a", "text": "Tamponade assessment is highlighted NCLEX priority."}, {"id": "b", "text": "Sternal precautions are highlighted NCLEX priority."}, {"id": "c", "text": "DAPT adherence post-PCI is highlighted NCLEX priority."}, {"id": "d", "text": "Tamponade surveillance is not needed after CABG in this note."}, {"id": "e", "text": "Medication adherence is optional after stent in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: NCLEX priorities emphasize post-CABG tamponade assessment, strict sternal precautions, and post-PCI DAPT compliance.', 'CABG and PCI - NCLEX', true, 100, 1, true);
